   134→static void
   135→stat_update_cb(EV_P_ ev_timer *watcher, int revents)
   136→{
   137→    struct sockaddr_un svaddr, claddr;
   138→    int sfd = -1;
   139→    size_t msgLen;
   140→    char resp[BUF_SIZE];
   141→
   142→    if (verbose) {
   143→        LOGI("update traffic stat: tx: %" PRIu64 " rx: %" PRIu64 "", tx, rx);
   144→    }
   145→
   146→    snprintf(resp, BUF_SIZE, "stat: {\"%s\":%" PRIu64 "}", server_port, tx + rx);
   147→    msgLen = strlen(resp) + 1;
   148→
   149→    ss_addr_t ip_addr = { .host = NULL, .port = NULL };
   150→    parse_addr(manager_address, &ip_addr);
   151→
   152→    if (ip_addr.host == NULL || ip_addr.port == NULL) {
   153→        sfd = socket(AF_UNIX, SOCK_DGRAM, 0);
   154→        if (sfd == -1) {
   155→            ERROR("stat_socket");
   156→            return;
   157→        }
   158→
   159→        memset(&claddr, 0, sizeof(struct sockaddr_un));
   160→        claddr.sun_family = AF_UNIX;
   161→        snprintf(claddr.sun_path, sizeof(claddr.sun_path), "/tmp/shadowsocks.%s", server_port);
   162→
   163→        unlink(claddr.sun_path);
   164→
   165→        if (bind(sfd, (struct sockaddr *)&claddr, sizeof(struct sockaddr_un)) == -1) {
   166→            ERROR("stat_bind");
   167→            close(sfd);
   168→            return;
   169→        }
   170→
   171→        memset(&svaddr, 0, sizeof(struct sockaddr_un));
   172→        svaddr.sun_family = AF_UNIX;
   173→        strncpy(svaddr.sun_path, manager_address, sizeof(svaddr.sun_path) - 1);
   174→
   175→        if (sendto(sfd, resp, strlen(resp) + 1, 0, (struct sockaddr *)&svaddr,
   176→                   sizeof(struct sockaddr_un)) != msgLen) {
   177→            ERROR("stat_sendto");
   178→            close(sfd);
   179→            return;
   180→        }
   181→
   182→        unlink(claddr.sun_path);
   183→    } else {
   184→        struct sockaddr_storage storage;
   185→        memset(&storage, 0, sizeof(struct sockaddr_storage));
   186→        if (get_sockaddr(ip_addr.host, ip_addr.port, &storage, 0, ipv6first) == -1) {
   187→            ERROR("failed to parse the manager addr");
   188→            return;
   189→        }
   190→
   191→        sfd = socket(storage.ss_family, SOCK_DGRAM, 0);
   192→
   193→        if (sfd == -1) {
   194→            ERROR("stat_socket");
   195→            return;
   196→        }
   197→
   198→        size_t addr_len = get_sockaddr_len((struct sockaddr *)&storage);
   199→        if (sendto(sfd, resp, strlen(resp) + 1, 0, (struct sockaddr *)&storage,
   200→                   addr_len) != msgLen) {
   201→            ERROR("stat_sendto");
   202→            close(sfd);
   203→            return;
   204→        }
   205→    }
   206→
   207→    close(sfd);
   208→}
