   222→static size_t
   223→parse_header_len(const char atyp, const char *data, size_t offset)
   224→{
   225→    size_t len = 0;
   226→    if ((atyp & ADDRTYPE_MASK) == 1) {
   227→        // IP V4
   228→        len += sizeof(struct in_addr);
   229→    } else if ((atyp & ADDRTYPE_MASK) == 3) {
   230→        // Domain name
   231→        uint8_t name_len = *(uint8_t *)(data + offset);
   232→        len += name_len + 1;
   233→    } else if ((atyp & ADDRTYPE_MASK) == 4) {
   234→        // IP V6
   235→        len += sizeof(struct in6_addr);
   236→    } else {
   237→        return 0;
   238→    }
   239→    len += 2;
   240→    return len;
   241→}
   242→
   243→static int
   244→is_header_complete(const buffer_t *buf)
   245→{
   246→    size_t header_len = 0;
   247→    size_t buf_len    = buf->len;
   248→
   249→    char atyp = buf->array[header_len];
   250→
   251→    // 1 byte for atyp
   252→    header_len++;
   253→
   254→    if ((atyp & ADDRTYPE_MASK) == 1) {
   255→        // IP V4
   256→        header_len += sizeof(struct in_addr);
   257→    } else if ((atyp & ADDRTYPE_MASK) == 3) {
   258→        // Domain name
   259→        // domain len + len of domain
   260→        if (buf_len < header_len + 1)
   261→            return 0;
   262→        uint8_t name_len = *(uint8_t *)(buf->array + header_len);
   263→        header_len += name_len + 1;
   264→    } else if ((atyp & ADDRTYPE_MASK) == 4) {
   265→        // IP V6
   266→        header_len += sizeof(struct in6_addr);
   267→    } else {
   268→        return -1;
   269→    }
   270→
   271→    // len of port
   272→    header_len += 2;
   273→
   274→    // size of ONETIMEAUTH_BYTES
   275→    if (auth || (atyp & ONETIMEAUTH_FLAG)) {
   276→        header_len += ONETIMEAUTH_BYTES;
   277→    }
   278→
   279→    return buf_len >= header_len ? 1 : 0;
   280→}
