   282→static char *
   283→get_peer_name(int fd)
   284→{
   285→    static char peer_name[INET6_ADDRSTRLEN] = { 0 };
   286→    struct sockaddr_storage addr;
   287→    socklen_t len = sizeof(struct sockaddr_storage);
   288→    memset(&addr, 0, len);
   289→    memset(peer_name, 0, INET6_ADDRSTRLEN);
   290→    int err = getpeername(fd, (struct sockaddr *)&addr, &len);
   291→    if (err == 0) {
   292→        if (addr.ss_family == AF_INET) {
   293→            struct sockaddr_in *s = (struct sockaddr_in *)&addr;
   294→            dns_ntop(AF_INET, &s->sin_addr, peer_name, INET_ADDRSTRLEN);
   295→        } else if (addr.ss_family == AF_INET6) {
   296→            struct sockaddr_in6 *s = (struct sockaddr_in6 *)&addr;
   297→            dns_ntop(AF_INET6, &s->sin6_addr, peer_name, INET6_ADDRSTRLEN);
   298→        }
   299→    } else {
   300→        return NULL;
   301→    }
   302→    return peer_name;
   303→}
