   342→int
   343→setfastopen(int fd)
   344→{
   345→    int s = 0;
   346→#ifdef TCP_FASTOPEN
   347→    if (fast_open) {
   348→#ifdef __APPLE__
   349→        int opt = 1;
   350→#else
   351→        int opt = 5;
   352→#endif
   353→        s = setsockopt(fd, IPPROTO_TCP, TCP_FASTOPEN, &opt, sizeof(opt));
   354→
   355→        if (s == -1) {
   356→            if (errno == EPROTONOSUPPORT || errno == ENOPROTOOPT) {
   357→                LOGE("fast open is not supported on this platform");
   358→            } else {
   359→                ERROR("setsockopt");
   360→            }
   361→        }
   362→    }
   363→#endif
   364→    return s;
   365→}
