   367→#ifndef __MINGW32__
   368→int
   369→setnonblocking(int fd)
   370→{
   371→    int flags;
   372→    if (-1 == (flags = fcntl(fd, F_GETFL, 0))) {
   373→        flags = 0;
   374→    }
   375→    return fcntl(fd, F_SETFL, flags | O_NONBLOCK);
